function findSingle(nums) {
    let left = 0, right = nums.length - 1;

    while (left < right) {
        let mid = Math.floor((left + right) / 2);

        // Make sure mid is even
        if (mid % 2 === 1) mid--;

        if (nums[mid] === nums[mid + 1]) {
            left = mid + 2; // single element is in the right half
